function solve(n) {
    // Map to store the sums and the pairs that produce them.
    // Key: sum (a^3 + b^3)
    // Value: Array of pairs [a, b]
    const sumsMap = new Map();

    // Since a and b are positive integers and a <= b,
    // a^3 + b^3 <= n.
    // Since a >= 1, we must have b^3 < n, so b < n^(1/3).
    // A safe upper bound for b is Math.floor(n^(1/3)) + 1.
    // Since n <= 10^9, n^(1/3) <= 1000. Let's use 1000 + 2 for safety.
    const maxB = Math.floor(Math.pow(n, 1/3)) + 2;

    for (let b = 1; b < maxB; b++) {
        const bCubed = b * b * b;

        // Since a <= b, a^3 <= b^3.
        // Also, a^3 + b^3 <= n, so a^3 <= n - b^3.
        const maxACubed = n - bCubed;

        if (maxACubed < 1) {
            // If even a=1 yields a sum > n, we can stop increasing b, 
            // although the loop condition should handle this.
            break;
        }

        // a <= b and a^3 <= n - b^3
        // The maximum possible 'a' is min(b, floor((n - b^3)^(1/3)))
        let maxA = Math.floor(Math.pow(maxACubed, 1/3));
        maxA = Math.min(b, maxA);

        for (let a = 1; a <= maxA; a++) {
            const aCubed = a * a * a;
            const sum = aCubed + bCubed;

            if (sum > n) {
                // Since a is increasing, any further sum will also be > n.
                break; 
            }

            if (!sumsMap.has(sum)) {
                sumsMap.set(sum, []);
            }

            // Store the pair (a, b) where a <= b is guaranteed by the loops
            sumsMap.get(sum).push([a, b]);
        }
    }

    const goodNumbers = [];

    // Iterate through the map to find numbers that have at least two distinct representations.
    for (const [sum, pairs] of sumsMap.entries()) {
        if (pairs.length >= 2) {
            // Check if the pairs are genuinely distinct in terms of sets {a, b}
            // Since we iterate with a <= b, and we only store [a, b], 
            // if two pairs are generated, they must represent different combinations 
            // unless a pair [a, b] is generated twice, which is impossible with this iteration structure.

            // However, the problem definition requires "at least two groups of different integer pairs (a, b)".
            // Since we enforce a <= b, if we find two entries in the 'pairs' array, they must correspond
            // to different (a, b) pairs.

            goodNumbers.push(sum);
        }
    }

    // Return the good numbers sorted in ascending order
    return goodNumbers.sort((x, y) => x - y);
}

