func solve(n int64) []int64 {
	// Map to store the sums and the count of distinct pairs that produce them.
	// Key: sum (a^3 + b^3)
	// Value: count of pairs
	sumsMap := make(map[int64]int)

	// Since a and b are positive integers and a <= b,
	// a^3 + b^3 <= n.
	// Since a >= 1, we must have b^3 < n, so b < n^(1/3).

	// Calculate the maximum possible value for b.
	// b_max_float = n^(1/3)
	// Since n <= 10^9, n^(1/3) <= 1000. We can iterate up to this limit.
	bMaxFloat := math.Pow(float64(n), 1.0/3.0)
	bMax := int64(bMaxFloat) + 1

	// Iterate through b starting from 1
	for b := int64(1); b <= bMax; b++ {
		bCubed := b * b * b

		// If bCubed itself is already greater than n, we can stop (though bMax should prevent this)
		if bCubed >= n {
			break
		}

		// a <= b and a^3 <= n - b^3
		maxACubed := n - bCubed

		// Find the maximum 'a' such that a^3 <= maxACubed and a <= b
		maxAFloat := math.Pow(float64(maxACubed), 1.0/3.0)
		maxA := int64(math.Min(float64(b), maxAFloat))

		// Iterate through a starting from 1
		for a := int64(1); a <= maxA; a++ {
			aCubed := a * a * a
			sum := aCubed + bCubed

			if sum > n {
				// Should not happen due to maxA calculation, but safe break
				break 
			}

			// Since we iterate a <= b, any pair [a, b] found here is unique in its ordered form.
			sumsMap[sum]++
		}
	}

	var goodNumbers []int64

	// Iterate through the map to find numbers that have at least two distinct representations.
	for sum, count := range sumsMap {
		if count >= 2 {
			goodNumbers = append(goodNumbers, sum)
		}
	}

	// Return the good numbers sorted in ascending order
	sort.Slice(goodNumbers, func(i, j int) bool {
		return goodNumbers[i] < goodNumbers[j]
	})

	return goodNumbers
}
